import{_ as n,o as e,c as l,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 14 章 把模糊需求变成可验收任务","description":"“帮我整理一下”“做得专业一点”“分析这批材料”都不是可以直接执行的任务。小白使用 WorkBuddy 最重要的一步，是把模糊想法变成目标明确、边界清楚、结果可验收的任务卡。 任务开始前回答七个问题：为什么做、给谁看、用什么材料、产出什么、何时完成、如何验收、哪些事情不能做。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 14 章 生活助手的价值，是减少琐碎/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 14 章 生活助手的价值，是减少琐碎/index.md","lastUpdated":1784290813000}'),i={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 14 章 生活助手的价值，是减少琐碎/index.md"};function t(r,a,o,p,h,d){return e(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="第-14-章-把模糊需求变成可验收任务" tabindex="-1">第 14 章 把模糊需求变成可验收任务 <a class="header-anchor" href="#第-14-章-把模糊需求变成可验收任务" aria-label="Permalink to &quot;第 14 章 把模糊需求变成可验收任务&quot;">​</a></h1><p>“帮我整理一下”“做得专业一点”“分析这批材料”都不是可以直接执行的任务。小白使用 WorkBuddy 最重要的一步，是把模糊想法变成目标明确、边界清楚、结果可验收的任务卡。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>需求只有一句话，不知道从哪里开始。</li><li>输入材料很多，但不知道哪些有用。</li><li>反复修改仍不满意，却说不清问题。</li><li>需要把任务交给同事或以后重复使用。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>任务开始前回答七个问题：为什么做、给谁看、用什么材料、产出什么、何时完成、如何验收、哪些事情不能做。</p><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><h3 id="_1-让-ai-先提问" tabindex="-1">1. 让 AI 先提问 <a class="header-anchor" href="#_1-让-ai-先提问" aria-label="Permalink to &quot;1. 让 AI 先提问&quot;">​</a></h3><p>要求 WorkBuddy 用不超过八个问题收集任务约束。回答不了的问题标记待确认，不用猜测填满。</p><h3 id="_2-形成任务卡" tabindex="-1">2. 形成任务卡 <a class="header-anchor" href="#_2-形成任务卡" aria-label="Permalink to &quot;2. 形成任务卡&quot;">​</a></h3><p>任务卡包含背景、目标、读者、输入、输出、步骤、验收、安全边界和截止时间。</p><h3 id="_3-先交付最小样本" tabindex="-1">3. 先交付最小样本 <a class="header-anchor" href="#_3-先交付最小样本" aria-label="Permalink to &quot;3. 先交付最小样本&quot;">​</a></h3><p>长报告先做一页，批量文件先做三个，复杂分析先给字段和口径。样本确认后再扩大范围。</p><h3 id="_4-用验收语言反馈" tabindex="-1">4. 用验收语言反馈 <a class="header-anchor" href="#_4-用验收语言反馈" aria-label="Permalink to &quot;4. 用验收语言反馈&quot;">​</a></h3><p>不要只说“感觉不对”。指出哪项验收标准未满足，例如数字无来源、结构缺章节、语气不适合目标读者。</p><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>原需求是“整理一下本月工作”。澄清后变成：读取三个脱敏周报，面向内部复盘，输出一页摘要和待办清单；事实必须标注来源，不补造结果，不外发。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我有一个初步需求：{一句话需求}。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请先不要执行。用不超过 8 个问题帮助我澄清：</span></span>
<span class="line"><span>1. 任务目标和使用对象；</span></span>
<span class="line"><span>2. 输入材料和可用范围；</span></span>
<span class="line"><span>3. 输出物、格式和篇幅；</span></span>
<span class="line"><span>4. 截止时间和优先级；</span></span>
<span class="line"><span>5. 验收标准；</span></span>
<span class="line"><span>6. 必须保留和禁止修改的内容；</span></span>
<span class="line"><span>7. 权限、脱敏和外发边界。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>根据我的回答生成任务卡，并建议一个最小可验收样本。</span></span>
<span class="line"><span>没有我确认，不开始批量处理。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>目标和读者是否真实明确。</li><li>输入材料是否完整并有使用权限。</li><li>输出格式和验收标准是否可以检查。</li><li>样本是否通过，是否允许扩大范围。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>任务卡没有“整理好一点”之类不可检查的要求。</li><li>每项输出都有格式、范围和质量标准。</li><li>缺失信息、风险和禁止动作单独列出。</li><li>样本确认记录可作为后续修改依据。</li></ul><h2 id="常见弯路与可复用资产" tabindex="-1">常见弯路与可复用资产 <a class="header-anchor" href="#常见弯路与可复用资产" aria-label="Permalink to &quot;常见弯路与可复用资产&quot;">​</a></h2><ul><li>一句话直接开工，通常导致返工。先澄清再执行。</li><li>一次处理全部材料，问题会批量放大。先做最小样本。</li><li>反馈只说“不够专业”，AI无法定位。把反馈写成验收差距。</li><li>可复用任务卡、澄清问题清单、样本确认单和验收表。</li></ul>`,25)])])}const b=n(i,[["render",t]]);export{u as __pageData,b as default};
